514	// computeProviderPerformance computes latency percentiles and success rate from outcomes.
515	// Returns -1 sentinels when sample_count < 3 per FEAT-014.
516	func computeProviderPerformance(outcomes []agent.RoutingOutcome) ProviderPerformance {
517		perf := ProviderPerformance{
518			P50LatencyMS: -1,
519			P95LatencyMS: -1,
520			SuccessRate:  -1,
521			SampleCount:  len(outcomes),
522			Window:       "7d",
523		}
524		if len(outcomes) < 3 {
525			return perf
526		}
527		var successCount int
528		latencies := make([]int, 0, len(outcomes))
529		for _, o := range outcomes {
530			if o.Success {
531				successCount++
532			}
533			latencies = append(latencies, o.LatencyMS)
534		}
535		perf.SuccessRate = float64(successCount) / float64(len(outcomes))
536		sort.Ints(latencies)
537		perf.P50LatencyMS = latencies[len(latencies)/2]
538		p95Idx := int(float64(len(latencies)-1) * 0.95)
