855	// harnessInfoToRoutingSignal translates an upstream HarnessInfo into the
856	// RoutingSignalSnapshot shape consumers still emit. Introduced when the
857	// DDx-side provider-native parsers were retired (ddx-7bc0c8d5): upstream
858	// quota.Status values ("ok|stale|unavailable") map to the existing
859	// freshness vocabulary so the JSON output for `ddx agent doctor --routing`
860	// keeps its previous field layout. The source kind is passed through as
861	// provided; DDx must not synthesize a cache label when the service leaves it
862	// empty.
863	func harnessInfoToRoutingSignal(info agentlib.HarnessInfo, now time.Time) agent.RoutingSignalSnapshot {
864		if info.Quota == nil && len(info.UsageWindows) == 0 && info.Account == nil {
865			return agent.RoutingSignalSnapshot{}
866		}
867	
868		snap := agent.RoutingSignalSnapshot{Provider: info.Name}
869		if info.Account != nil && (info.Account.Email != "" || info.Account.PlanType != "" || info.Account.OrgName != "") {
870			snap.Account = &agent.AccountInfo{
871				Email:    info.Account.Email,
872				PlanType: info.Account.PlanType,
873				OrgName:  info.Account.OrgName,
874			}
875		}
876	
877		if info.Quota != nil {
878			freshness := "fresh"
879			if !info.Quota.Fresh {
880				freshness = "stale"
881			}
882			if info.Quota.Status == "unavailable" || info.Quota.Status == "unauthenticated" {
883				freshness = "unknown"
884			}
885			kind := info.Quota.Source
886			var ageSeconds int64
887			if !info.Quota.CapturedAt.IsZero() {
888				if age := now.UTC().Sub(info.Quota.CapturedAt.UTC()); age > 0 {
889					ageSeconds = int64(age.Seconds())
890				}
891			}
892			meta := agent.SignalSourceMetadata{
893				Provider:   info.Name,
894				Kind:       kind,
895				ObservedAt: info.Quota.CapturedAt.UTC(),
896				Freshness:  freshness,
897				AgeSeconds: ageSeconds,
898			}
899			state := "unknown"
900			switch info.Quota.Status {
901			case "ok":
902				state = "ok"
903			case "stale":
904				state = "ok"
905			}
906			var usedPercent, windowMinutes int
907			var resetsAt string
908			for _, w := range info.Quota.Windows {
909				snap.QuotaWindows = append(snap.QuotaWindows, agent.QuotaWindow{
910					Name:          w.Name,
911					LimitID:       w.LimitID,
912					WindowMinutes: w.WindowMinutes,
913					UsedPercent:   w.UsedPercent,
914					ResetsAt:      w.ResetsAt,
915					ResetsAtUnix:  w.ResetsAtUnix,
916					State:         w.State,
917				})
918				if w.LimitID == "extra" {
919					continue
920				}

