 29	
 30		if w.Code != http.StatusOK {
 31			t.Fatalf("expected 200, got %d", w.Code)
 32		}
 33	
 34		var items []ProviderSummary
 35		if err := json.NewDecoder(w.Body).Decode(&items); err != nil {
 36			t.Fatalf("decode: %v", err)
 37		}
 38		if len(items) == 0 {
 39			t.Fatal("expected non-empty provider list")
 40		}
 41	
 42		// Verify required fields are present and not fabricated as "ok"/"0" when unknown.
 43		svc, err := agent.NewServiceFromWorkDir(dir)
