 53			harnessNames[info.Name] = true
 54		}
 55	
 56		for _, item := range items {
 57			if item.Harness == "" {
 58				t.Error("provider summary missing harness field")
 59			}
 60			if !harnessNames[item.Harness] {
 61				t.Errorf("unexpected harness in response: %q", item.Harness)
 62			}
 63			if item.DisplayName == "" {
 64				t.Errorf("harness %q missing display_name", item.Harness)
 65			}
 66			// Status must be one of the defined values.
 67			switch item.Status {
 68			case "available", "unavailable", "unknown":
 69			default:
 70				t.Errorf("harness %q has invalid status %q", item.Harness, item.Status)
