369	// TestProviderPerformanceWithData verifies performance metrics with sample data.
370	func TestProviderPerformanceWithData(t *testing.T) {
371		now := time.Date(2026, 4, 14, 12, 0, 0, 0, time.UTC)
372	
373		// Generate 5 outcomes within the 7d window.
374		outcomes := []agent.RoutingOutcome{
375			{Harness: "claude", ObservedAt: now.Add(-1 * time.Hour), Success: true, LatencyMS: 1000},
376			{Harness: "claude", ObservedAt: now.Add(-2 * time.Hour), Success: true, LatencyMS: 2000},
377			{Harness: "claude", ObservedAt: now.Add(-3 * time.Hour), Success: false, LatencyMS: 3000},
378			{Harness: "claude", ObservedAt: now.Add(-4 * time.Hour), Success: true, LatencyMS: 4000},
379			{Harness: "claude", ObservedAt: now.Add(-5 * time.Hour), Success: true, LatencyMS: 5000},
380		}
381	
382		perf := computeProviderPerformance(outcomes)
383		if perf.SampleCount != 5 {
384			t.Errorf("sample_count = %d, want 5", perf.SampleCount)
385		}
386		// 4/5 = 0.8 success rate
387		if perf.SuccessRate != 0.8 {
388			t.Errorf("success_rate = %v, want 0.8", perf.SuccessRate)
389		}
390		// Sorted latencies: [1000, 2000, 3000, 4000, 5000] — p50 = index 2 = 3000
391		if perf.P50LatencyMS != 3000 {
392			t.Errorf("p50_latency_ms = %d, want 3000", perf.P50LatencyMS)
393		}
394		// p95 index = int(4 * 0.95) = int(3.8) = 3 → latency[3] = 4000
395		if perf.P95LatencyMS != 4000 {
396			t.Errorf("p95_latency_ms = %d, want 4000", perf.P95LatencyMS)
397		}
398	}
